import os
import json
import re
from http.server import HTTPServer, BaseHTTPRequestHandler
from datetime import datetime
from threading import Lock
from urllib.parse import urlparse, parse_qs

# Configuration
LOG_DIR = os.environ.get("LOG_DIR", "./logs")
LOG_FILE = os.environ.get("LOG_FILE", "app.log")
HOST = os.environ.get("LOG_HOST", "0.0.0.0")
PORT = int(os.environ.get("LOG_PORT", "8080"))
MAX_LOG_SIZE = int(os.environ.get("MAX_LOG_SIZE", str(10 * 1024 * 1024)))  # 10MB default
API_KEY = os.environ.get("LOG_API_KEY", "")  # Optional API key for auth

VALID_LOG_LEVELS = ("DEBUG", "INFO", "WARNING", "ERROR", "CRITICAL")

# Ensure log directory exists
os.makedirs(LOG_DIR, exist_ok=True)

file_lock = Lock()


def sanitize_input(value):
    """Sanitize input to prevent log injection attacks."""
    if not isinstance(value, str):
        value = str(value)
    # Remove newlines and carriage returns to prevent log injection
    value = value.replace("\n", "\\n").replace("\r", "\\r")
    # Remove null bytes
    value = value.replace("\x00", "")
    return value


def validate_service_name(name):
    """Validate service name contains only safe characters."""
    if not name:
        return False
    pattern = re.compile(r"^[a-zA-Z0-9_\-\.]+$")
    return bool(pattern.match(name))


def rotate_log_if_needed(log_path):
    """Rotate log file if it exceeds MAX_LOG_SIZE."""
    try:
        if os.path.exists(log_path) and os.path.getsize(log_path) > MAX_LOG_SIZE:
            timestamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
            rotated_path = "%s.%s" % (log_path, timestamp)
            os.rename(log_path, rotated_path)
            return True
    except OSError:
        pass
    return False


def write_log_entry(service, level, message, metadata=None, trace_id=None, span_id=None):
    """Write a formatted log entry to the log file."""
    timestamp = datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%S.%fZ")
    log_path = os.path.join(LOG_DIR, LOG_FILE)

    # Sanitize all inputs
    service = sanitize_input(service)
    level = sanitize_input(level)
    message = sanitize_input(message)

    # Build log line
    log_line = "[%s] [%s] [%s]" % (timestamp, level, service)

    if trace_id:
        log_line = "%s [trace_id=%s]" % (log_line, sanitize_input(trace_id))

    if span_id:
        log_line = "%s [span_id=%s]" % (log_line, sanitize_input(span_id))

    log_line = "%s %s" % (log_line, message)

    if metadata:
        if isinstance(metadata, dict):
            meta_parts = []
            for key, value in metadata.items():
                meta_parts.append("%s=%s" % (sanitize_input(key), sanitize_input(value)))
            log_line = "%s | metadata: %s" % (log_line, ", ".join(meta_parts))
        else:
            log_line = "%s | metadata: %s" % (log_line, sanitize_input(str(metadata)))

    log_line = "%s\n" % log_line

    with file_lock:
        rotate_log_if_needed(log_path)
        with open(log_path, "a", encoding="utf-8") as f:
            f.write(log_line)

    return log_line.strip()


def write_service_log(service, level, message, metadata=None, trace_id=None, span_id=None):
    """Write a log entry to a service-specific log file."""
    timestamp = datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%S.%fZ")
    service_log_file = "%s.log" % service
    log_path = os.path.join(LOG_DIR, service_log_file)

    service = sanitize_input(service)
    level = sanitize_input(level)
    message = sanitize_input(message)

    log_line = "[%s] [%s] %s" % (timestamp, level, message)

    if trace_id:
        log_line = "[%s] [%s] [trace_id=%s] %s" % (
            timestamp, level, sanitize_input(trace_id), message
        )

    if metadata and isinstance(metadata, dict):
        meta_parts = []
        for key, value in metadata.items():
            meta_parts.append("%s=%s" % (sanitize_input(key), sanitize_input(value)))
        log_line = "%s | %s" % (log_line, ", ".join(meta_parts))

    log_line = "%s\n" % log_line

    with file_lock:
        rotate_log_if_needed(log_path)
        with open(log_path, "a", encoding="utf-8") as f:
            f.write(log_line)


class LogRequestHandler(BaseHTTPRequestHandler):
    """HTTP request handler for the logging service."""

    def log_message(self, format, *args):
        """Override to suppress default HTTP server logging to stderr."""
        # Write access logs to a separate file
        timestamp = datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%S.%fZ")
        access_log_path = os.path.join(LOG_DIR, "access.log")
        log_line = "[%s] %s - %s\n" % (timestamp, self.client_address[0], format % args)
        with file_lock:
            with open(access_log_path, "a", encoding="utf-8") as f:
                f.write(log_line)

    def _check_auth(self):
        """Check API key if configured."""
        if not API_KEY:
            return True
        auth_header = self.headers.get("X-API-Key", "")
        if auth_header == API_KEY:
            return True
        self._send_response(401, {"error": "Unauthorized", "message": "Invalid or missing API key"})
        return False

    def _send_response(self, status_code, body):
        """Send a JSON response."""
        response_body = json.dumps(body).encode("utf-8")
        self.send_response(status_code)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", str(len(response_body)))
        self.end_headers()
        self.wfile.write(response_body)

    def _read_body(self):
        """Read and parse JSON request body."""
        content_length = int(self.headers.get("Content-Length", 0))
        if content_length == 0:
            return None
        if content_length > 1024 * 1024:  # 1MB limit
            return None
        raw_body = self.rfile.read(content_length)
        try:
            return json.loads(raw_body.decode("utf-8"))
        except (json.JSONDecodeError, UnicodeDecodeError):
            return None

    def do_GET(self):
        """Handle GET requests."""
        parsed = urlparse(self.path)

        if parsed.path == "/health":
            self._send_response(200, {
                "status": "healthy",
                "timestamp": datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%S.%fZ"),
                "log_dir": LOG_DIR,
                "log_file": LOG_FILE
            })
            return

        if parsed.path == "/logs":
            if not self._check_auth():
                return
            self._handle_get_logs(parsed)
            return

        if parsed.path == "/services":
            if not self._check_auth():
                return
            self._handle_get_services()
            return

        self._send_response(404, {"error": "Not found"})

    def do_POST(self):
        """Handle POST requests."""
        parsed = urlparse(self.path)

        if parsed.path == "/log":
            if not self._check_auth():
                return
            self._handle_single_log()
            return

        if parsed.path == "/logs/batch":
            if not self._check_auth():
                return
            self._handle_batch_logs()
            return

        self._send_response(404, {"error": "Not found"})

    def _handle_single_log(self):
        """Handle a single log entry submission."""
        body = self._read_body()
        if body is None:
            self._send_response(400, {"error": "Invalid JSON body"})
            return

        # Validate required fields
        service = body.get("service", "")
        level = body.get("level", "INFO").upper()
        message = body.get("message", "")
        metadata = body.get("metadata", None)
        trace_id = body.get("trace_id", None)
        span_id = body.get("span_id", None)

        if not service:
            self._send_response(400, {"error": "Missing required field: service"})
            return

        if not validate_service_name(service):
            self._send_response(400, {
                "error": "Invalid service name. Use only alphanumeric, hyphens, underscores, dots."
            })
            return

        if not message:
            self._send_response(400, {"error": "Missing required field: message"})
            return

        if level not in VALID_LOG_LEVELS:
            self._send_response(400, {
                "error": "Invalid log level. Must be one of: %s" % ", ".join(VALID_LOG_LEVELS)
            })
            return

        # Write to main log file
        log_entry = write_log_entry(service, level, message, metadata, trace_id, span_id)

        # Also write to service-specific log
        write_service_log(service, level, message, metadata, trace_id, span_id)

        self._send_response(200, {
            "status": "logged",
            "entry": log_entry
        })

    def _handle_batch_logs(self):
        """Handle batch log entry submission."""
        body = self._read_body()
        if body is None:
            self._send_response(400, {"error": "Invalid JSON body"})
            return

        entries = body.get("entries", [])
        if not isinstance(entries, list):
            self._send_response(400, {"error": "entries must be a list"})
            return

        if len(entries) > 1000:
            self._send_response(400, {"error": "Maximum 1000 entries per batch"})
            return

        results = []
        errors = []

        for i, entry in enumerate(entries):
            service = entry.get("service", "")
            level = entry.get("level", "INFO").upper()
            message = entry.get("message", "")
            metadata = entry.get("metadata", None)
            trace_id = entry.get("trace_id", None)
            span_id = entry.get("span_id", None)

            if not service or not validate_service_name(service):
                errors.append({"index": i, "error": "Invalid or missing service name"})
                continue

            if not message:
                errors.append({"index": i, "error": "Missing message"})
                continue

            if level not in VALID_LOG_LEVELS:
                level = "INFO"

            log_entry = write_log_entry(service, level, message, metadata, trace_id, span_id)
            write_service_log(service, level, message, metadata, trace_id, span_id)
            results.append({"index": i, "status": "logged"})

        self._send_response(200, {
            "status": "completed",
            "logged": len(results),
            "errors": len(errors),
            "error_details": errors
        })

    def _handle_get_logs(self, parsed):
        """Handle retrieving log entries."""
        params = parse_qs(parsed.query)
        service = params.get("service", [None])[0]
        level = params.get("level", [None])[0]
        lines = int(params.get("lines", ["100"])[0])
        lines = min(lines, 10000)  # Cap at 10000 lines

        if service and validate_service_name(service):
            log_path = os.path.join(LOG_DIR, "%s.log" % service)
        else:
            log_path = os.path.join(LOG_DIR, LOG_FILE)

        if not os.path.exists(log_path):
            self._send_response(200, {"logs": [], "count": 0})
            return

        try:
            with open(log_path, "r", encoding="utf-8") as f:
                all_lines = f.readlines()

            # Filter by level if specified
            if level and level.upper() in VALID_LOG_LEVELS:
                level_filter = "[%s]" % level.upper()
                all_lines = [line for line in all_lines if level_filter in line]

            # Return last N lines
            result_lines = all_lines[-lines:]
            result_lines = [line.strip() for line in result_lines]

            self._send_response(200, {
                "logs": result_lines,
                "count": len(result_lines),
                "total_available": len(all_lines)
            })
        except IOError as e:
            self._send_response(500, {"error": "Failed to read logs: %s" % str(e)})

    def _handle_get_services(self):
        """List all services that have log files."""
        services = []
        try:
            for filename in os.listdir(LOG_DIR):
                if filename.endswith(".log") and filename not in (LOG_FILE, "access.log"):
                    service_name = filename[:-4]  # Remove .log extension
                    file_path = os.path.join(LOG_DIR, filename)
                    stat = os.stat(file_path)
                    services.append({
                        "name": service_name,
                        "log_file": filename,
                        "size_bytes": stat.st_size,
                        "last_modified": datetime.utcfromtimestamp(
                            stat.st_mtime
                        ).strftime("%Y-%m-%dT%H:%M:%S.%fZ")
                    })
        except OSError as e:
            self._send_response(500, {"error": "Failed to list services: %s" % str(e)})
            return

        self._send_response(200, {
            "services": services,
            "count": len(services)
        })


class LogClient:
    """Client library for sending logs to the logging service."""

    def __init__(self, host="localhost", port=8080, service_name="unknown", api_key=""):
        self.base_url = "http://%s:%d" % (host, port)
        self.service_name = service_name
        self.api_key = api_key

    def _send(self, endpoint, data):
        """Send a log request using urllib."""
        import urllib.request
        import urllib.error

        url = "%s%s" % (self.base_url, endpoint)
        json_data = json.dumps(data).encode("utf-8")

        req = urllib.request.Request(url, data=json_data, method="POST")
        req.add_header("Content-Type", "application/json")
        if self.api_key:
            req.add_header("X-API-Key", self.api_key)

        try:
            with urllib.request.urlopen(req, timeout=5) as response:
                return json.loads(response.read().decode("utf-8"))
        except urllib.error.URLError as e:
            return {"error": str(e)}

    def log(self, level, message, metadata=None, trace_id=None, span_id=None):
        """Send a single log entry."""
        data = {
            "service": self.service_name,
            "level": level,
            "message": message,
        }
        if metadata:
            data["metadata"] = metadata
        if trace_id:
            data["trace_id"] = trace_id
        if span_id:
            data["span_id"] = span_id
        return self._send("/log", data)

    def debug(self, message, **kwargs):
        return self.log("DEBUG", message, **kwargs)

    def info(self, message, **kwargs):
        return self.log("INFO", message, **kwargs)

    def warning(self, message, **kwargs):
        return self.log("WARNING", message, **kwargs)

    def error(self, message, **kwargs):
        return self.log("ERROR", message, **kwargs)

    def critical(self, message, **kwargs):
        return self.log("CRITICAL", message, **kwargs)

    def batch(self, entries):
        """Send multiple log entries at once.

        entries: list of dicts with keys: level, message, metadata (optional), trace_id (optional)
        """
        formatted = []
        for entry in entries:
            formatted.append({
                "service": self.service_name,
                "level": entry.get("level", "INFO"),
                "message": entry.get("message", ""),
                "metadata": entry.get("metadata"),
                "trace_id": entry.get("trace_id"),
                "span_id": entry.get("span_id"),
            })
        return self._send("/logs/batch", {"entries": formatted})


def run_server(host=HOST, port=PORT):
    """Start the logging HTTP server."""
    server = HTTPServer((host, port), LogRequestHandler)
    startup_msg = "Centralized Logging Service started on %s:%d" % (host, port)
    print(startup_msg)
    print("Log directory: %s" % os.path.abspath(LOG_DIR))
    print("Main log file: %s" % LOG_FILE)
    if API_KEY:
        print("API key authentication: ENABLED")
    else:
        print("API key authentication: DISABLED (set LOG_API_KEY env var to enable)")

    # Log the startup
    write_log_entry("log-server", "INFO", startup_msg)

    print("\nEndpoints:")
    print("  POST /log          - Submit a single log entry")
    print("  POST /logs/batch   - Submit multiple log entries")
    print("  GET  /logs         - Retrieve log entries (?service=X&level=Y&lines=N)")
    print("  GET  /services     - List all services with logs")
    print("  GET  /health       - Health check")
    print("\nPress Ctrl+C to stop.\n")

    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print("\nShutting down logging service...")
        write_log_entry("log-server", "INFO", "Logging service shutting down")
        server.server_close()


